// // This LFSR module is designed to generate pseudo-random sequences by shifting its value on each clock cycle and applying a feedback mechanism using taps at certain bits determined by a polynomial. However, it does not reset to a user-defined seed value.
module LFSR_32bit(  
    input clk,  
    input reset,  
    input [31:0] seed,  
    output reg [31:0] lfsr_out  
);  
    always @(posedge clk or posedge reset) begin  
        if (reset) begin  
            lfsr_out <= seed;  
        end else begin  
            lfsr_out <= {lfsr_out[30:0], lfsr_out[31] ^ lfsr_out[21] ^ lfsr_out[1] ^ lfsr_out[0]};  
        end  
    end  
endmodule
